import { createContext, useContext, useState, useEffect } from 'react';
import { notify } from './notification.helpers';

export interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

export const NotificationContext = createContext(null);

export const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notification, setNotification] = useState<NotificationProps | null>(null);

  useEffect(() => {
    if (notificationElem) {
      const handleNotification = async (props: NotificationProps) => {
        try {
          await notify(notificationElem, props);
          setNotification(props);
        } catch (error) {
          console.error(error);
        }
      };
      return () => {
        setNotification(null);
      };
    }
  }, [notificationElem]);

  const triggerNotification = async (props: NotificationProps) => {
    await handleNotification(props);
  };

  return {
    triggerNotification,
  };
};
